[CmdletBinding()]param();$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;. (Join-Path $root 'tests/helpers/TypedStudioFixture.ps1');. (Join-Path $root 'scripts/records/Test-StudioRecord.ps1');$work=Join-Path ([IO.Path]::GetTempPath()) ('frontend-'+[guid]::NewGuid().ToString('N'));New-Item -ItemType Directory $work|Out-Null
